import{c as a,Q as e,j as r,m as n}from"./chunks/framework.DpF7k2f3.js";const h=JSON.parse('{"title":"第7章 AIエージェントコアロジック","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ja/part2-fundamentals/chapter7.md","filePath":"ja/part2-fundamentals/chapter7.md"}'),o={name:"ja/part2-fundamentals/chapter7.md"};function l(s,t,p,i,c,d){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="第7章-aiエージェントコアロジック" tabindex="-1">第7章 AIエージェントコアロジック <a class="header-anchor" href="#第7章-aiエージェントコアロジック" aria-label="Permalink to &quot;第7章 AIエージェントコアロジック&quot;">​</a></h1><h2 id="本章で学べること" tabindex="-1">本章で学べること <a class="header-anchor" href="#本章で学べること" aria-label="Permalink to &quot;本章で学べること&quot;">​</a></h2><p>基础篇の最后一章恭喜你！</p><p>前面的章节教你「怎么用AI」なら、この章は「怎么让AI自己干活」を教えます。</p><p>先に聞きたい：大模型和AI Agent的核心区别是什么？</p><p>大模型是被动的——你问，它答，一问一答，天花板很低。AI Agent是主动的——你给它一个目标，它自己想办法、自己查资料、自己调用工具、自己验证结果，直到任务完成。</p><p>从「你告诉我怎么做」到「你自己看着办」，这是质的飞跃。</p><p>读完这章你会带走：</p><ul><li><strong>Agentの本质理解</strong>：为什么Agent是AI应用的未来</li><li><strong>Agent架构全貌</strong>：感知、推理、行动、记忆四大组件</li><li><strong>工具调用能力</strong>：让AI能够操作真实世界（含生产级代码）</li><li><strong>规划推理模式</strong>：ReAct完整追踪、LangGraph 2026实战、Plan-and-Execute</li><li><strong>多Agent协作</strong>：两个真实可用的案例</li><li><strong>Agent可靠性工程</strong>：失败的6种模式、成本控制、输出校验</li></ul><hr><blockquote><p><strong>全文の翻訳は後日公開予定、しばらくお待ちください。中文版は今すぐ読めます。</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter7.html">中文版阅读</a></p></blockquote>',11)])])}const u=a(o,[["render",l]]);export{h as __pageData,u as default};
